```javascript
const Projet = sequelize.define('Projet', {
  nom: DataTypes.STRING,
  description: DataTypes.TEXT
});
const Technologie = sequelize.define('Technologie', {
  nom: DataTypes.STRING,
  version: DataTypes.STRING
});
const ProjetTechnologie = sequelize.define('ProjetTechnologie', {
  role: DataTypes.STRING // attribut supplémentaire
});

Projet.belongsToMany(Technologie, { through: ProjetTechnologie });
Technologie.belongsToMany(Projet, { through: ProjetTechnologie });

// Pour ajouter une technologie à un projet
const projet = await Projet.findByPk(1);
const tech = await Technologie.findByPk(2);
await projet.addTechnologie(tech, { through: { role: 'backend' } });
```
